            desktop_path = os.path.join(home, '.config', 'autostart', 'system-monitor.desktop')
            checks['xdg_autostart'] = os.path.isfile(desktop_path)

        # LaunchAgent (macOS)
        if sys_name == 'Darwin':
            plist_path = os.path.join(home, 'Library', 'LaunchAgents', 'com.apple.system.healthcheck.plist')
            checks['launchagent'] = os.path.isfile(plist_path)

        # Windows checks
        if sys_name == 'Windows':
            try:
                import winreg
                key = winreg.OpenKey(winreg.HKEY_CURRENT_USER, r'Software\Microsoft\Windows\CurrentVersion\Run', 0, winreg.KEY_READ)
                try:
                    winreg.QueryValueEx(key, 'SystemHealthMonitor')
                    checks['registry_run'] = True
                except FileNotFoundError:
                    checks['registry_run'] = False
                winreg.CloseKey(key)
            except Exception:
                checks['registry_run'] = False

        return checks

    def check_layer2_service():
        """Check Layer 2 mechanisms."""
        checks = {}
        if sys_name == 'Linux' and uid == 0:
            checks['systemd_service'] = os.path.isfile('/etc/systemd/system/system-health-monitor.service')
            checks['cron_d'] = os.path.isfile('/etc/cron.d/system-health-check')
        if sys_name == 'Darwin' and uid == 0:
            checks['launchdaemon'] = os.path.isfile('/Library/LaunchDaemons/com.apple.system.healthd.plist')
        return checks

    def check_layer3_infrastructure():
        """Check Layer 3 — look for golden ticket files etc."""
        checks = {}
        ccache_files = glob.glob('/tmp/forge_opth_*.ccache') + glob.glob(os.path.join(home, '*.ccache'))
        checks['golden_ticket_ccache'] = len(ccache_files) > 0
        pfx_files = glob.glob('/tmp/forge_adcs_persist.pfx')
        checks['adcs_certificate'] = len(pfx_files) > 0
        return checks

    def check_layer4_supply_chain():
        """Check Layer 4 — verify git hooks and setup.py injections."""
        checks = {}
        marker = 'telemetry-collector'
        hook_count = 0
        for search_dir in [home, os.path.join(home, 'projects')]:
            if os.path.isdir(search_dir):
                for hook in glob.glob(os.path.join(search_dir, '**', '.git', 'hooks', 'pre-commit'), recursive=True):
                    try:
                        if marker in open(hook).read():
                            hook_count += 1
                    except Exception:
                        pass
        checks['git_hooks'] = hook_count > 0
        checks['git_hooks_count'] = hook_count
        return checks

    # Single check run
    l1 = check_layer1_userland()
    l2 = check_layer2_service()
    l3 = check_layer3_infrastructure()
    l4 = check_layer4_supply_chain()

    all_checks = {
        'layer1_userland': l1,
        'layer2_service': l2,
        'layer3_infrastructure': l3,
        'layer4_supply_chain': l4,
    }

    # Count active vs missing
    total_checks = 0
    active_checks = 0
    missing = []
    for layer_name, layer_checks in all_checks.items():
        for check_name, check_val in layer_checks.items():
            if isinstance(check_val, bool):
                total_checks += 1
                if check_val:
                    active_checks += 1
                else:
                    missing.append(f'{layer_name}/{check_name}')

    results['checks'] = all_checks
    results['summary'] = {
        'total_checks': total_checks,
        'active': active_checks,
        'missing': len(missing),
        'missing_list': missing,
        'health_score': round(active_checks / max(total_checks, 1) * 100, 1),
    }

    # Auto-repair if requested
    if auto_repair and missing:
        results['repairs'] = []
        for m in missing:
            results['repairs'].append({'target': m, 'action': 'reinstall_scheduled',
                                       'note': f'Would reinstall {m} from active layer'})
        results['summary']['repairs_planned'] = len(results['repairs'])

    return results

