    out = run_persistence_watchdog(auto_repair=True)
    print(json.dumps(out, indent=2, default=str))
    score = out['summary']['health_score']
    print(f"\nPersistence Health: {score}% ({out['summary']['active']}/{out['summary']['total_checks']} active)")
    if out['summary']['missing'] > 0:
        print(f"Missing: {', '.join(out['summary']['missing_list'])}")
